// Format Q1 of newly-created quiz + 4 inline buttons
const row = $input.first().json;
const quizId = row.id;
const chatId = row.chat_id;
const questions = (row.questions && row.questions.questions) || row.questions;
const q = questions[0];

const text = `🎯 *Question 1 of 5*\n\n${q.question}\n\n*A)* ${q.options.A}\n*B)* ${q.options.B}\n*C)* ${q.options.C}\n*D)* ${q.options.D}`;

const reply_markup = {
  inline_keyboard: [
    [
      { text: 'A', callback_data: `ans:${quizId}:${q.id}:A` },
      { text: 'B', callback_data: `ans:${quizId}:${q.id}:B` },
    ],
    [
      { text: 'C', callback_data: `ans:${quizId}:${q.id}:C` },
      { text: 'D', callback_data: `ans:${quizId}:${q.id}:D` },
    ],
  ]
};

return [{ json: { chat_id: chatId, text, reply_markup } }];

// Parse answer callback: ans:<quiz_id>:Qn:X
const cb = $input.first().json.callback_query;
const data = cb.data || '';
const parts = data.split(':');
if (parts.length !== 4 || parts[0] !== 'ans') {
  throw new Error('Malformed answer callback: ' + data);
}
const quizId = parseInt(parts[1], 10);
const questionId = parts[2];
const userAnswer = parts[3].toUpperCase();
const chatId = cb.message.chat.id;
const messageId = cb.message.message_id;

return [{ json: { quiz_id: quizId, question_id: questionId, user_answer: userAnswer, chat_id: chatId, message_id: messageId } }];

// Validate answer, build next-state payload (next Q or final results)
const quizRow = $input.first().json;
const { quiz_id, question_id, user_answer, chat_id } = $('ans: parse callback').item.json;

const rawQuestions = quizRow.questions;
const questions = (rawQuestions && rawQuestions.questions) || rawQuestions;
const qIdx = questions.findIndex(q => q.id === question_id);
if (qIdx < 0) throw new Error('Question ' + question_id + ' not in quiz ' + quiz_id);

const q = questions[qIdx];
const correctAnswer = String(q.correctAnswer).toUpperCase();
const correct = user_answer === correctAnswer;
const isLast = qIdx === questions.length - 1;
const nextIdx = qIdx + 1;

// Build payload for downstream INSERT into quiz_answers
const payload = {
  quiz_id,
  question_id,
  user_answer,
  correct_answer: correctAnswer,
  correct,
  is_last: isLast,
  chat_id,
  current_q_idx: qIdx,
  next_q_idx: nextIdx,
  questions, // pass forward for downstream formatting
  user_option_text: q.options[user_answer] || '',
  correct_option_text: q.options[correctAnswer] || '',
  explanation: q.explanation || '',
};

return [{ json: payload }];

// Build final results message — score + per-Q feedback with explanations on wrong
const answers = $input.all().map(i => i.json);
const chatId = $('ans: validate').item.json.chat_id;
const quizId = $('ans: validate').item.json.quiz_id;

const raw = answers[0]?.questions;
const questions = (raw && raw.questions) || raw;

const correctCount = answers.filter(a => a.correct).length;
const total = answers.length;
const pct = Math.round(100 * correctCount / total);

let badge;
if (pct >= 80) badge = '🏆';
else if (pct >= 60) badge = '✅';
else if (pct >= 40) badge = '⚠️';
else badge = '🔻';

const lines = [`${badge} *Quiz complete: ${correctCount}/${total} (${pct}%)*`, ''];

for (const a of answers) {
  const q = questions.find(qq => qq.id === a.question_id);
  const mark = a.correct ? '✅' : '❌';
  const userOpt = q?.options?.[a.user_answer] || '';
  const correctLetter = q?.correctAnswer || '?';
  const correctOpt = q?.options?.[correctLetter] || '';

  lines.push(`${mark} *${a.question_id}* — you picked _${a.user_answer}_: ${userOpt}`);
  if (!a.correct) {
    lines.push(`     ✓ Correct: *${correctLetter}* — ${correctOpt}`);
    if (q?.explanation) lines.push(`     💡 _${q.explanation}_`);
  }
  lines.push('');
}

lines.push(pct >= 80
  ? `_Strong recall — this material is well-internalised._`
  : pct >= 60
    ? `_Solid baseline — re-skim the points you missed._`
    : `_Worth a deeper re-read — consider running /quiz on this topic again later._`);

lines.push('');
lines.push('Use `/quiz` to test another topic, or `/learn <url>` to add a new one.');

return [{ json: { chat_id: chatId, text: lines.join('\n') } }];

// Format next question (nextIdx already computed by 'ans: validate')
const v = $('ans: validate').item.json;
const questions = v.questions;
const nextQ = questions[v.next_q_idx];
const chatId = v.chat_id;
const quizId = v.quiz_id;
const qNum = v.next_q_idx + 1;

const prevMark = v.correct ? '✅ correct' : `❌ wrong (was *${v.correct_answer}*)`;

const text = `${prevMark}\n\n🎯 *Question ${qNum} of 5*\n\n${nextQ.question}\n\n*A)* ${nextQ.options.A}\n*B)* ${nextQ.options.B}\n*C)* ${nextQ.options.C}\n*D)* ${nextQ.options.D}`;

const reply_markup = {
  inline_keyboard: [
    [
      { text: 'A', callback_data: `ans:${quizId}:${nextQ.id}:A` },
      { text: 'B', callback_data: `ans:${quizId}:${nextQ.id}:B` },
    ],
    [
      { text: 'C', callback_data: `ans:${quizId}:${nextQ.id}:C` },
      { text: 'D', callback_data: `ans:${quizId}:${nextQ.id}:D` },
    ],
  ]
};

return [{ json: { chat_id: chatId, text, reply_markup } }];

// Format /stats dashboard
const chatId = $('Telegram Trigger').item.json.message.chat.id;
const row = $input.first().json;

if (!row || row.materials_count === undefined || row.materials_count === null) {
  return [{ json: { chat_id: chatId, text: '📊 *No learning history yet.*\n\nSend `/learn <url>` to add your first material — once you take a quiz, your stats will show up here.' } }];
}

function bar(n, total = 10) {
  const filled = Math.min(total, Math.max(0, Math.round((n / 100) * total)));
  return '█'.repeat(filled) + '░'.repeat(total - filled);
}

const score = Number(row.avg_score_pct) || 0;
const lastQuiz = row.last_quiz_at ? new Date(row.last_quiz_at).toISOString().split('T')[0] : 'never';

const lines = [
  '📊 *Your learning dashboard*',
  '',
  `📚 *Materials saved:* ${row.materials_count}`,
  `   🟢 beginner: ${row.beginner_materials || 0}`,
  `   🟡 intermediate: ${row.intermediate_materials || 0}`,
  `   🔴 advanced: ${row.advanced_materials || 0}`,
  '',
  `🎯 *Quizzes taken:* ${row.quizzes_taken || 0}`,
  `📈 *Average score:* ${score}%`,
  `      \`${bar(score)}\``,
  `🕒 *Last quiz:* ${lastQuiz}`,
  '',
  '_Tip: re-quiz a topic after a few days to test retention._',
];

return [{ json: { chat_id: chatId, text: lines.join('\n') } }];
